"use client"

/**
 * Flying Letters Component
 * 
 * Creates animated flying letters/envelopes that float across the background
 * Inspired by the design model with letters flying from a mailbox
 */
export function FlyingLetters() {
  // Generate random letters with different positions, sizes, and animation delays
  const letters = Array.from({ length: 12 }, (_, i) => ({
    id: i,
    size: Math.random() * 20 + 15, // 15-35px
    x: Math.random() * 100, // 0-100% horizontal position
    y: Math.random() * 100, // 0-100% vertical position
    duration: Math.random() * 20 + 15, // 15-35s animation duration
    delay: Math.random() * 5, // 0-5s delay
    rotation: Math.random() * 360, // Random rotation
  }))

  return (
    <div className="absolute inset-0 overflow-hidden pointer-events-none">
      {letters.map((letter) => (
        <div
          key={letter.id}
          className="absolute opacity-[0.12]"
          style={{
            left: `${letter.x}%`,
            top: `${letter.y}%`,
            width: `${letter.size}px`,
            height: `${letter.size * 0.7}px`,
            animation: `float-letter ${letter.duration}s ease-in-out infinite`,
            animationDelay: `${letter.delay}s`,
            transform: `rotate(${letter.rotation}deg)`,
          }}
        >
          {/* Envelope SVG - blue like in design model */}
          <svg
            viewBox="0 0 24 24"
            fill="none"
            className="w-full h-full"
            style={{ filter: 'blur(0.8px)' }}
          >
            <path
              d="M4 4h16c1.1 0 2 .9 2 2v12c0 1.1-.9 2-2 2H4c-1.1 0-2-.9-2-2V6c0-1.1.9-2 2-2z"
              stroke="rgb(59, 130, 246)"
              strokeWidth="1.5"
              fill="rgba(59, 130, 246, 0.15)"
            />
            <path
              d="M22 6l-10 7L2 6"
              stroke="rgb(59, 130, 246)"
              strokeWidth="1.5"
              strokeLinecap="round"
            />
          </svg>
        </div>
      ))}
    </div>
  )
}
